import React, { useEffect, useState } from "react";

function App() {
  let [przepisyBaza, setPrzepisyBaza] = useState([]);
  let [przepisyApi, setPrzepisyApi] = useState([]);
  let [ulubione, setUlubione] = useState([]);
  let [search, setSearch] = useState("");
  let [loading, setLoading] = useState(false);

  let uzytkownikId = 1;

  useEffect(() => {
    fetch("http://localhost:5000/przepisy")
      .then((response) => response.json())
      .then((data) => {
        if (Array.isArray(data)) {
          setPrzepisyBaza(data);
        } else {
          setPrzepisyBaza([]);
        }
      })
      .catch((error) => {
        console.log(error);
        setPrzepisyBaza([]);
      });

    pobierzUlubione();
  }, []);

  function pobierzUlubione() {
    fetch("http://localhost:5000/ulubione/uzytkownik/" + uzytkownikId)
      .then((response) => response.json())
      .then((data) => {
        if (Array.isArray(data)) {
          setUlubione(data);
        } else {
          setUlubione([]);
        }
      })
      .catch((error) => {
        console.log(error);
        setUlubione([]);
      });
  }

  function szukajPrzepisu() {
    if (!search.trim()) {
      return;
    }

    setLoading(true);

    fetch("http://localhost:5000/api/przepisy/szukaj/" + search)
      .then((response) => response.json())
      .then((data) => {
        if (Array.isArray(data)) {
          setPrzepisyApi(data);
        } else {
          setPrzepisyApi([]);
        }

        setLoading(false);
      })
      .catch((error) => {
        console.log(error);
        setPrzepisyApi([]);
        setLoading(false);
      });
  }

  function dodajDoUlubionych(apiPrzepisId) {
    fetch("http://localhost:5000/ulubione-api", {
      method: "POST",
      headers: {
        "Content-Type": "application/json"
      },
      body: JSON.stringify({
        uzytkownik_id: uzytkownikId,
        api_przepis_id: apiPrzepisId
      })
    })
      .then((response) => response.json())
      .then((data) => {
        console.log("Dodano:", data);
        alert("Dodano do ulubionych");
        pobierzUlubione();
      })
      .catch((error) => {
        console.log(error);
        alert("Błąd podczas dodawania");
      });
  }

  function usunZUlubionych(apiPrzepisId) {
    fetch(
      "http://localhost:5000/ulubione-api/" + uzytkownikId + "/" + apiPrzepisId,
      {
        method: "DELETE"
      }
    )
      .then((response) => response.json())
      .then((data) => {
        console.log("Usunięto:", data);
        alert("Usunięto z ulubionych");
        pobierzUlubione();
      })
      .catch((error) => {
        console.log(error);
        alert("Błąd podczas usuwania");
      });
  }

  function czyJestWUlubionych(apiPrzepisId) {
    return ulubione.some((item) => item.api_przepis_id === apiPrzepisId);
  }

  return (
    <div style={{ padding: "20px", fontFamily: "Arial" }}>
      <h1>Culinary Book</h1>

      <hr />

      <h2>Wyszukiwarka przepisów z API</h2>

      <div style={{ marginBottom: "20px" }}>
        <input
          type="text"
          placeholder="Wpisz nazwę przepisu, np. chicken"
          value={search}
          onChange={(e) => setSearch(e.target.value)}
          style={{
            padding: "10px",
            width: "300px",
            marginRight: "10px"
          }}
        />
        <button onClick={szukajPrzepisu} style={{ padding: "10px 20px" }}>
          Szukaj
        </button>
      </div>

      {loading && <p>Ładowanie danych z API...</p>}

      {przepisyApi.length === 0 ? (
        <p>Brak wyników z API</p>
      ) : (
        przepisyApi.map((recipe) => (
          <div
            key={recipe.id}
            style={{
              border: "1px solid #ccc",
              marginBottom: "20px",
              padding: "15px",
              borderRadius: "8px"
            }}
          >
            <h3>{recipe.tytul}</h3>
            <p><strong>Kategoria:</strong> {recipe.kategoria}</p>

            {recipe.obrazek && (
              <img
                src={recipe.obrazek}
                alt={recipe.tytul}
                style={{ width: "250px", display: "block", marginBottom: "10px" }}
              />
            )}

            {recipe.youtube && (
              <p>
                <a href={recipe.youtube} target="_blank" rel="noreferrer">
                  Obejrzyj na YouTube
                </a>
              </p>
            )}

            {recipe.instrukcje && (
              <p>{recipe.instrukcje.substring(0, 200)}...</p>
            )}

            {czyJestWUlubionych(recipe.id) ? (
              <button onClick={() => usunZUlubionych(recipe.id)}>
                Usuń z ulubionych
              </button>
            ) : (
              <button onClick={() => dodajDoUlubionych(recipe.id)}>
                Dodaj do ulubionych
              </button>
            )}
          </div>
        ))
      )}

      <hr />

      <h2>Ulubione użytkownika</h2>

      {ulubione.length === 0 ? (
        <p>Brak ulubionych</p>
      ) : (
        ulubione.map((item) => (
          <div
            key={item.id}
            style={{
              border: "1px solid #999",
              marginBottom: "10px",
              padding: "10px",
              borderRadius: "8px"
            }}
          >
            <p><strong>ID użytkownika:</strong> {item.uzytkownik_id}</p>
            <p><strong>ID przepisu z API:</strong> {item.api_przepis_id}</p>
          </div>
        ))
      )}

      <hr />

      <h2>Przepisy z bazy danych</h2>

      {przepisyBaza.length === 0 ? (
        <p>Brak danych z bazy</p>
      ) : (
        przepisyBaza.map((przepis) => (
          <div
            key={przepis.id}
            style={{
              border: "1px solid #ccc",
              marginBottom: "20px",
              padding: "15px",
              borderRadius: "8px"
            }}
          >
            <h3>{przepis.tytul}</h3>
            <p><strong>Czas:</strong> {przepis.czas_przygotowania_min} min</p>
            <p><strong>Trudność:</strong> {przepis.poziom_trudnosci}</p>
            <p><strong>Dieta:</strong> {przepis.dieta}</p>
            <p>{przepis.opis}</p>
          </div>
        ))
      )}
    </div>
  );
}

export default App;
